css:
.loader {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
  display: inline-flex;
  gap: 5px;
}.loader:before,.loader:after {content: "";
  width: 25px;
  aspect-ratio: 1;
  box-shadow: 0 0 0 3px inset var(--loader-bg, #ffffff);
  animation: l4 1.5s infinite;
}.loader:before {--s: -1;
  animation-delay: 0.75s}@keyframes l4 {0% {transform: scale(var(--s,1)) translate(0) rotate(0)}16.67% {transform: scale(var(--s,1)) translate(-50%) rotate(0)}33.33% {transform: scale(var(--s,1)) translate(-50%) rotate(90deg)}50%,100% {transform: scale(var(--s,1)) translate(0) rotate(90deg)}}
